1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const COMPONENT_BLOCK_OF_3_PRICE = 60;
4	const CURSE_SURCHARGE_RATE = 0.5;
5	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	type Item = { type: string; cursed?: boolean };
17	type QuoteStep = { type: "quote"; items: Item[] };
18	type Scenario = { steps: QuoteStep[] };
19	
20	function groupByType(items: Item[]): Map<string, Item[]> {
21	  const groups = new Map<string, Item[]>();
22	  for (const item of items) {
23	    const group = groups.get(item.type) ?? [];
24	    group.push(item);
25	    groups.set(item.type, group);
26	  }
27	  return groups;
28	}
29	
30	function calculateItemPremium(item: Item): number {
31	  const itemBase = BASE_PREMIUMS[item.type];
32	  const curseSurcharge = item.cursed ? itemBase * CURSE_SURCHARGE_RATE : 0;
33	  return itemBase + curseSurcharge;
34	}
35	
36	function calculateGroupPremium(type: string, group: Item[]): number {
37	  if (COMPONENT_TYPES.has(type) && group.length === 3) {
38	    return COMPONENT_BLOCK_OF_3_PRICE;
39	  }
40	  return group.reduce((sum, item) => sum + calculateItemPremium(item), 0);
41	}
42	
43	function calculateBasePremium(items: Item[]): number {
44	  return Array.from(groupByType(items)).reduce(
45	    (total, [type, group]) => total + calculateGroupPremium(type, group),
46	    0,
47	  );
48	}
49	
50	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
51	  const { steps } = scenario as Scenario;
52	  const items = steps[0].items;
53	  const basePremium = calculateBasePremium(items);
54	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
55	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
56	  return { results: [{ premium }] };
57	}
